#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, a, b, k[10005], zans = -1;
bool vis[1050];
struct POS
{
	int pos, ans;
	POS(int x, int y)
	{
		pos = x, ans = y;
	}
};
void bfs()
{
	queue<POS>q;
	q.push(POS(a, 0));
	while (!q.empty())
	{
		int now = q.front().pos, ansn = q.front().ans;
		q.pop();
		if (now < 1 || now > n)continue;
		if (vis[now] == 1)continue;
		vis[now] = 1;
		if (now == b)
		{
			zans = ansn;
			return;
		}
		q.push(POS(now - k[now], ansn + 1));
		q.push(POS(now + k[now], ansn + 1));
	}
}
int main(void)
{
	cin >> n >> a >> b;
	for (int i = 1; i <= n; i++)cin >> k[i];
	bfs();
	cout << zans;
	return false;
}
